import{LyapunovFractals}from"./class.min.js";import{DownloadHighResButton}from"/scripts/components/buttons.min.js";import{TextBox}from"/scripts/components/textBoxes.min.js";import{$}from"/scripts/src/main.min.js";export default function(){const n=new LyapunovFractals({canvas:$("#output-canvas")}),e=(new DownloadHighResButton({element:$("#download-dropdown"),applet:n,filename:()=>"a-lyapunov-fractal.png"}),new TextBox({element:$("#resolution-input"),name:"Resolution",value:1e3,minValue:100,maxValue:2e3,onInput:function(){n.resolution=e.value,n.wilson.resizeCanvas({width:n.resolution})}})),t=new TextBox({element:$("#generating-string-input"),name:"Generating String",value:"AB",onInput:o});function o(){n.run({generatingString:t.value.toUpperCase()})}o()}